SELECT id, clinic_name, contact_name, phone, region, scale, remark, status, created_at, updated_at, deleted FROM sys_trial_application WHERE deleted = 0
AND (clinic_name LIKE CONCAT('%', #{keyword}, '%') OR contact_name LIKE CONCAT('%', #{keyword}, '%') OR phone LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY id DESC LIMIT #{size} OFFSET #{offset}
